import {
  Users,
  Shield,
  Package,
  ClipboardList,
  Activity,
} from "lucide-react"

interface Props {
  employees: any[]
  assets: any[]
  requests: any[]
  logs: any[]
}

export default function DashboardCards({
  employees,
  assets,
  requests,
  logs,
}: Props) {
  return (
    <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-5 gap-6 mb-10">

      <div className="bg-white rounded-3xl p-6 shadow-sm hover:shadow-lg transition-all duration-200">

        <Users size={28} />

        <p className="text-gray-500 mt-5">
          Employees
        </p>

        <h2 className="text-4xl font-black mt-2">
          {employees.length}
        </h2>

      </div>

      <div className="bg-white rounded-3xl p-6 shadow-sm hover:shadow-lg transition-all duration-200">

        <Shield size={28} />

        <p className="text-gray-500 mt-5">
          Admin
        </p>

        <h2 className="text-4xl font-black mt-2">
          {
            employees.filter(
              (e: any) =>
                e.role === "admin"
            ).length
          }
        </h2>

      </div>

      <div className="bg-white rounded-3xl p-6 shadow-sm hover:shadow-lg transition-all duration-200">

        <Package size={28} />

        <p className="text-gray-500 mt-5">
          Assets
        </p>

        <h2 className="text-4xl font-black mt-2">
          {assets.length}
        </h2>

      </div>

      <div className="bg-white rounded-3xl p-6 shadow-sm hover:shadow-lg transition-all duration-200">

        <ClipboardList size={28} />

        <p className="text-gray-500 mt-5">
          Requests
        </p>

        <h2 className="text-4xl font-black mt-2">
          {requests.length}
        </h2>

      </div>

      <div className="bg-white rounded-3xl p-6 shadow-sm hover:shadow-lg transition-all duration-200">

        <Activity size={28} />

        <p className="text-gray-500 mt-5">
          Logs
        </p>

        <h2 className="text-4xl font-black mt-2">
          {logs.length}
        </h2>

      </div>

    </div>
  )
}